# app/retrieval/ranker.py
from app.flags import get_bool

def rank_results(results: list, query: str, user_id: str, category: str) -> list:
    """
    Route to new ranker only for the query categories it was designed for.
    The flag store targeting rule: enabled if category in [product_faq, how_to].
    """
    flag_ctx = {
        "key": user_id,
        "custom": {
            "query_category": category,
            "query_length_bucket": "short" if len(query) < 50 else "long",
        }
    }

    if get_bool("genai.experimental_ranking", flag_ctx):
        return rank_v2(results, query)

    return rank_v1(results, query)

# app/api/chat.py
from app.flags import get_bool
import logging

log = logging.getLogger(__name__)

def handle_chat_request(user_query: str, user_id: str) -> dict:
    """
    Kill switch pattern: feature defaults to enabled; incident ops flip to disabled.
    The flag name follows the convention: {team}.kill.{feature}
    """
    if not get_bool("genai.kill.advanced_reasoning", {"key": user_id}):
        # Kill switch is OFF (flag=false means the feature is disabled)
        log.warning("advanced_reasoning kill switch active; falling back to standard mode")
        return handle_standard_chat(user_query, user_id)

    return handle_advanced_chat(user_query, user_id)
